// packages/database/src/db/relations/messaging.ts
// Grouped relations for messaging domain (generated by scripts/split-relations.ts)

import { relations } from 'drizzle-orm/relations'
import {
  ChatAttachment,
  ChatMessage,
  ChatSession,
  ChatWidget,
  Comment,
  EmailAttachment,
  EmailEmbedding,
  Group,
  Inbox,
  InboxGroupAccess,
  InboxIntegration,
  InboxMemberAccess,
  Integration,
  IntegrationTagLabel,
  Label,
  LabelsOnThread,
  Message,
  MessageParticipant,
  OperatingHours,
  Organization,
  OrganizationMember,
  Participant,
  PromptHistory,
  Signature,
  Tag,
  TagsOnThread,
  Thread,
  ThreadParticipant,
  ThreadReadStatus,
  User,
  UserInboxUnreadCount,
} from '../schema'

export const inboxRelations = relations(Inbox, ({ one, many }) => ({
  organization: one(Organization, {
    fields: [Inbox.organizationId],
    references: [Organization.id],
  }),
  integrations: many(InboxIntegration),
  memberAccess: many(InboxMemberAccess),
  groupAccess: many(InboxGroupAccess),
  unreadCounts: many(UserInboxUnreadCount),
  // Note: threads relation removed - Thread.inboxId was removed in migration 0028
}))

export const inboxIntegrationRelations = relations(InboxIntegration, ({ one }) => ({
  inbox: one(Inbox, {
    fields: [InboxIntegration.inboxId],
    references: [Inbox.id],
  }),
  integration: one(Integration, {
    fields: [InboxIntegration.integrationId],
    references: [Integration.id],
  }),
}))

export const inboxMemberAccessRelations = relations(InboxMemberAccess, ({ one }) => ({
  inbox: one(Inbox, {
    fields: [InboxMemberAccess.inboxId],
    references: [Inbox.id],
  }),
  organizationMember: one(OrganizationMember, {
    fields: [InboxMemberAccess.organizationMemberId],
    references: [OrganizationMember.id],
  }),
}))

export const inboxGroupAccessRelations = relations(InboxGroupAccess, ({ one }) => ({
  group: one(Group, {
    fields: [InboxGroupAccess.groupId],
    references: [Group.id],
  }),
  inbox: one(Inbox, {
    fields: [InboxGroupAccess.inboxId],
    references: [Inbox.id],
  }),
}))

export const threadReadStatusRelations = relations(ThreadReadStatus, ({ one }) => ({
  organization: one(Organization, {
    fields: [ThreadReadStatus.organizationId],
    references: [Organization.id],
  }),
  thread: one(Thread, {
    fields: [ThreadReadStatus.threadId],
    references: [Thread.id],
  }),
  user: one(User, {
    fields: [ThreadReadStatus.userId],
    references: [User.id],
  }),
}))

export const threadRelations = relations(Thread, ({ one, many }) => ({
  readStatusEntries: many(ThreadReadStatus),
  messages: many(Message),
  assignee: one(User, {
    fields: [Thread.assigneeId],
    references: [User.id],
  }),
  // Note: inbox relation removed - Thread.inboxId was removed in migration 0028
  integration: one(Integration, {
    fields: [Thread.integrationId],
    references: [Integration.id],
  }),
  organization: one(Organization, {
    fields: [Thread.organizationId],
    references: [Organization.id],
  }),
  participants: many(ThreadParticipant),
  comments: many(Comment),
  chatSessions: many(ChatSession),
  chatMessages: many(ChatMessage),
  labels: many(LabelsOnThread),
  tags: many(TagsOnThread),
}))

export const userInboxUnreadCountRelations = relations(UserInboxUnreadCount, ({ one }) => ({
  inbox: one(Inbox, {
    fields: [UserInboxUnreadCount.inboxId],
    references: [Inbox.id],
  }),
  organization: one(Organization, {
    fields: [UserInboxUnreadCount.organizationId],
    references: [Organization.id],
  }),
  user: one(User, {
    fields: [UserInboxUnreadCount.userId],
    references: [User.id],
  }),
}))

export const labelRelations = relations(Label, ({ one, many }) => ({
  organization: one(Organization, {
    fields: [Label.organizationId],
    references: [Organization.id],
  }),
  integrationTagLabels: many(IntegrationTagLabel),
  threads: many(LabelsOnThread),
}))

export const messageRelations = relations(Message, ({ one, many }) => ({
  emailEmbeddings: many(EmailEmbedding),
  createdBy: one(User, {
    fields: [Message.createdById],
    references: [User.id],
  }),
  from: one(Participant, {
    fields: [Message.fromId],
    references: [Participant.id],
    relationName: 'message_fromId_participant_id',
  }),
  integration: one(Integration, {
    fields: [Message.integrationId],
    references: [Integration.id],
  }),
  organization: one(Organization, {
    fields: [Message.organizationId],
    references: [Organization.id],
  }),
  replyTo: one(Participant, {
    fields: [Message.replyToId],
    references: [Participant.id],
    relationName: 'message_replyToId_participant_id',
  }),
  signature: one(Signature, {
    fields: [Message.signatureId],
    references: [Signature.id],
  }),
  thread: one(Thread, {
    fields: [Message.threadId],
    references: [Thread.id],
  }),
  participants: many(MessageParticipant),
  attachments: many(EmailAttachment),
}))

export const messageParticipantRelations = relations(MessageParticipant, ({ one }) => ({
  message: one(Message, {
    fields: [MessageParticipant.messageId],
    references: [Message.id],
  }),
  participant: one(Participant, {
    fields: [MessageParticipant.participantId],
    references: [Participant.id],
  }),
}))



